def look_and_say(n):
    current = "1"
    for _ in range(n - 1):
        result = []
        count = 1
        for i in range(len(current)):
            if i + 1 < len(current) and current[i] == current[i + 1]:
                count += 1
            else:
                result.append(str(count) + current[i])
                count = 1
        current = "".join(result)
    return current

